async def execute(self, inputs):
    # Helper to convert to best possible type for comparison
    def convert(val):
        if val is None: return 0
        try:
            return float(val)
        except (ValueError, TypeError):
            return str(val)

    raw_a = inputs.get('a')
    raw_b = inputs.get('b')
    op = inputs.get('operation', '==')

    a = convert(raw_a)
    b = convert(raw_b)

    self.log_info(f"Comparing: {a} ({type(a).__name__}) {op} {b} ({type(b).__name__})")

    try:
        if op == '==': res = a == b
        elif op == '!=': res = a != b
        elif op == '>': res = a > b
        elif op == '<': res = a < b
        elif op == '>=': res = a >= b
        elif op == '<=': res = a <= b
        else: res = False

        return {'result': res}
    except Exception as e:
        self.log_error(f"Comparison logic error: {e}")
        return {'result': False}
